export const getFlagEmoji = (countryCode: string): string =>
    countryCode
        .toUpperCase()
        .replace(/./g, (char) =>
            String.fromCodePoint(127397 + char.charCodeAt(0))
        );

// Export an array for dropdowns if needed
export const CountryCodes = Object.entries(CountryCodesObject).map(
    ([code, { name, dial_code }]) => ({
        label: `${getFlagEmoji(code)} ${name} ${dial_code}`,
        value: dial_code,
    })
);

/**
 * useOutsideClick - Calls the callback when a click occurs outside the given ref.
 *
 * @param ref - React ref of the element to detect outside clicks for
 * @param callback - Function to call when an outside click is detected
 */

export const useOutsideClick = (
    ref: RefObject<HTMLElement | null>,
    callback: () => void
) => {
    useEffect(() => {
        const handleClick = (e: MouseEvent) => {
            if (ref.current && !ref.current.contains(e.target as Node)) {
                callback();
            }
        };

        document.addEventListener('mousedown', handleClick);

        return () => {
            document.removeEventListener('mousedown', handleClick);
        };
    }, [ref, callback]);
};

